/**
 * Get all unique stock symbols across all sub-industries
 */
export function getAllStocks() {
  const allStocks = new Set();
  Object.values(SUB_INDUSTRIES).forEach(stocks => {
    stocks.forEach(stock => allStocks.add(stock));
  });
  return Array.from(allStocks).sort();
}

/**
 * Get sub-industries for a specific stock symbol
 */
export function getSubIndustriesForStock(symbol) {
  const subIndustries = [];
  Object.entries(SUB_INDUSTRIES).forEach(([subIndustry, stocks]) => {
    if (stocks.includes(symbol)) {
      subIndustries.push(subIndustry);
    }
  });
  return subIndustries;
}

/**
 * Get stocks by sub-industry name
 */
export function getStocksBySubIndustry(subIndustryName) {
  return SUB_INDUSTRIES[subIndustryName] || [];
}

/**
 * Get all sub-industry names
 */
export function getAllSubIndustries() {
  return Object.keys(SUB_INDUSTRIES);
}

/**
 * Get total count of unique stocks
 */
export function getTotalStockCount() {
  return getAllStocks().length;
}
